import org.owasp.encoder.Encode;

public class XSSSecureCode {
    public static void main(String[] args) {
        // Simulating user input from a form
        String userInput = "<script>alert('XSS Attack!')</script>";

        // Sanitizing user input before including it in the HTML response
        String sanitizedUserInput = Encode.forHtml(userInput);

        // Generating the secure HTML output
        StringBuilder output = new StringBuilder();
        output.append("<html><body>Welcome, ");
        output.append(sanitizedUserInput);
        output.append("</body></html>");

        // Outputting the sanitized result
        System.out.println(output.toString());
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
